        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            int k = sc.nextInt();
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = sc.nextInt();
            }
            int min = a[0];
            for (int i = 1; i < n; i++) {
                if (a[i] < min) {
                    min = a[i];
                }
            }
            int flag = 1;
            for (int i = 0; i < n; i++) {
                if ((a[i] - min) % k != 0) {
                    flag = 0;
                    break;
                }
            }
            if (flag == 1) {
                System.out.println("YES");
            } else {
