const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
let input = [];
readline.on('line', line => {
    if (i == 0) {
        t = parseInt(line);
    } else {
        input.push(line.split(' ').map(x => parseInt(x)));
    }
    i++;
    if (i > t * 2) {
        for (let j = 0; j < t; j++) {
            let n = input[j * 2][0];
            let k = input[j * 2][1];
            let a = input[j * 2 + 1];
            let min = Math.min(...a);
            let flag = 1;
            for (let l = 0; l < n; l++) {
                if ((a[l] - min) % k != 0) {
                    flag = 0;
                    break;
                }
            }
            if (flag) {
                console.log('YES');
            } else {
                console.log('NO');
            }
        }
        readline.close();
    }
});
